INSERT INTO ingestion_run (ingester_name, ingester_version, status) VALUES ('seed-fsanz', '1.0.0', 'running');
INSERT INTO fact_evidence (source_name, source_url, source_section, snapshot_date, language, retrieved_by) VALUES ('FSANZ Food Standards Code Schedule 8 — Food additive names and code numbers', 'https://www.legislation.gov.au/F2015L00478/latest/text', 'Schedule 8 — Food additive names and code numbers', '2026-04-18', 'en', 'seed-fsanz:1.0.0') ON CONFLICT(source_url, snapshot_date) DO NOTHING;
INSERT INTO ingredient (canonical_id, primary_name, ingredient_class, ins_number, category, is_natural) VALUES ('NAME_this_standard_commences_on_1_march_2016_being_the_date_specified_as_the_commence', 'This Standard commences on 1 March 2016, being the date specified as the commencement date in notices in the Gazette and the New Zealand Gazette under section 92 of the Food Standards Australia New Zealand Act 1991 (Cth). See also section 93 of that Act. S8—2 Food additive names and code numbers For the definition of code number in section 1.1.2—2 and for subsection 1.2.4— 7(1), the food additive names and *code numbers are as listed in the following table (first in alphabetical order, then in numerical order): Food additive names—alphabetical listing Acacia or gum Arabic', 'substance', '414', 'food', 0) ON CONFLICT(canonical_id) DO NOTHING;
INSERT INTO ingredient_alias (canonical_id, alias, alias_normalized, alias_type, language_code, confidence, source) VALUES ('NAME_this_standard_commences_on_1_march_2016_being_the_date_specified_as_the_commence', 'This Standard commences on 1 March 2016, being the date specified as the commencement date in notices in the Gazette and the New Zealand Gazette under section 92 of the Food Standards Australia New Zealand Act 1991 (Cth). See also section 93 of that Act. S8—2 Food additive names and code numbers For the definition of code number in section 1.1.2—2 and for subsection 1.2.4— 7(1), the food additive names and *code numbers are as listed in the following table (first in alphabetical order, then in numerical order): Food additive names—alphabetical listing Acacia or gum Arabic', 'this standard commences on 1 march 2016, being the date specified as the commencement date in notices in the gazette and the new zealand gazette under section 92 of the food standards australia new zealand act 1991 (cth). see also section 93 of that act. s8—2 food additive names and code numbers for the definition of code number in section 1.1.2—2 and for subsection 1.2.4— 7(1), the food additive names and *code numbers are as listed in the following table (first in alphabetical order, then in numerical order): food additive names—alphabetical listing acacia or gum arabic', 'synonym', 'en', 1.0, 'FSANZ-Sched8') ON CONFLICT(alias_normalized, alias_type, COALESCE(language_code, '')) DO NOTHING;
